def calculate_fibonacci(n):
    if n <= 0:
        raise ValueError("Input must be a positive integer.")
    elif n == 1:
        return 0
    elif n == 2:
        return 1
    else:
        a, b = 0, 1
        for _ in range(2, n):
            a, b = b, a + b
        return b

# Edge case simulation
try:
    print(calculate_fibonacci(0))  # Raises ValueError
except ValueError as e:
    print(f"Edge case handled: {e}")

